export const generateImageForScene = async (parts: NarrationPart[], style: string, characters: Character[], artDirection: string, includeTextInImage: boolean): Promise<{ imageUrl: string, imagePrompt: string }> => {
    const ai = getAiClient();
    const textModel = 'gemini-3-flash-preview';
    const imageModel = 'gemini-2.5-flash-image';

    const charRef = characters.map(c => `CHARACTER BIBLE FOR ${c.name}: ${c.description}`).join('\n');
    const sceneContent = parts.map(p => p.text).join(' ');

    const systemInstruction = `
    You are a professional Cinematic Concept Artist. Your job is to write highly technical image generation prompts.

    STRICT VISUAL RULES:
    1. CURRENT GLOBAL STYLE: "${style}". 
    2. MANDATORY CONSISTENCY: Characters MUST look identical in every prompt. Use the Character Bible provided.
    3. NO STYLE DRIFT: If the style is "Cinematográfica" or "Realista", you are FORBIDDEN from using words like "cartoon", "disney", "pixar", "3d render", "whimsical", or "cute".
    4. TECHNICAL ANCHORING: Every prompt must start with technical camera and lighting terms related to "${style}".
    `;

    const promptGenPrompt = `
    GENERATE A TECHNICAL PROMPT FOR THIS SCENE:
    "${sceneContent}"

    USER STYLE CHOICE: ${style}
    ADDITIONAL ART DIRECTION: ${artDirection}

    CHARACTER CONSTANTS (STRICT ADHERENCE):
    ${charRef}

    PROMPT TEMPLATE:
    [TECHNICAL STYLE ANCHOR: ${style} lighting, ${style} camera settings] + [CHARACTER ACTION AND DESCRIPTION] + [ENVIRONMENT DETAILS] + [ART DIRECTION: ${artDirection}].

    Return ONLY the English prompt text.
    `;

    const promptResponse = await ai.models.generateContent({ 
        model: textModel, 
        contents: promptGenPrompt,
        config: { systemInstruction }
    });

    const imagePrompt = promptResponse.text;

    const imageResponse = await ai.models.generateContent({
        model: imageModel,
        contents: { parts: [{ text: imagePrompt }] },
        config: {
            imageConfig: {
                aspectRatio: "16:9" 
            }
        }
    });

    const candidate = imageResponse.candidates?.[0];
    const imagePart = candidate?.content?.parts?.find(p => p.inlineData);

    if (imagePart?.inlineData) {
        return {
            imageUrl: `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`,
            imagePrompt: imagePrompt
        };
    }
    throw new Error('La generación de imagen falló.');
};

export const generateVideoForScene = async (parts: NarrationPart[], aspectRatio: '16:9' | '9:16'): Promise<any> => {
    const ai = getAiClient();
    const model = 'veo-3.1-fast-generate-preview';
    const action = parts.filter(p => p.type !== 'INSTRUCTION').map(p => p.text).join(' ').substring(0, 500);

    return await ai.models.generateVideos({
        model,
        prompt: `Cinematic footage, high definition: ${action}. Strictly follow character visual consistency. Realistic textures, professional cinematography, NO animation style.`,
        config: { numberOfVideos: 1, resolution: '720p', aspectRatio }
    });
};

export const checkVideoStatus = async (operation: any): Promise<any> => {
    const ai = getAiClient();
    return await ai.operations.getVideosOperation({ operation });
};

export const generateAudioForScene = async (parts: NarrationPart[], allCharacters: Character[], narratorVoice: string): Promise<string> => {
    const ai = getAiClient();
    const model = 'gemini-2.5-flash-preview-tts';

    const speakableParts = parts.filter(p => p.type !== 'INSTRUCTION' && p.text.trim());
    const pcmChunks: Uint8Array[] = [];
    let totalLength = 0;

    for (const part of speakableParts) {
        const char = allCharacters.find(c => c.name === part.speaker);
        const voiceName = (part.type === 'DIALOGUE' && char?.voice) ? char.voice : narratorVoice;

        try {
            // Se usa el literal 'AUDIO' para asegurar la compatibilidad con el modelo TTS
            const response = await ai.models.generateContent({
                model,
                contents: [{ parts: [{ text: part.text }] }],
                config: {
                    responseModalities: ['AUDIO'],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName } },
                    },
                },
            });

            const candidate = response.candidates?.[0];
            const audioPart = candidate?.content?.parts?.find(p => p.inlineData);
            const data = audioPart?.inlineData?.data;

            if (data) {
                const pcm = decode(data);
                pcmChunks.push(pcm);
                totalLength += pcm.length;
            }
        } catch (e: any) {
            console.error("TTS Error:", e.message || e);
        }
    }

    if (pcmChunks.length === 0) throw new Error("No se pudo generar el audio.");

    const concatenated = new Uint8Array(totalLength);
    let offset = 0;
    for (const chunk of pcmChunks) {
        concatenated.set(chunk, offset);
        offset += chunk.length;
    }

    return URL.createObjectURL(createWavBlob(concatenated, 24000, 1, 16));
};

export interface Character {
  name: string;
  description: string;
  gender: 'MASCULINE' | 'FEMININE' | 'NEUTRAL';
  voice?: string;
}

export type NarrationPartType = 'NARRATION' | 'DIALOGUE' | 'INSTRUCTION';

export interface NarrationPart {
  type: NarrationPartType;
  speaker?: string;
  text: string;
}

export interface Scene {
  id: number;
  parts: NarrationPart[];
  imageUrl?: string;
  imagePrompt?: string;
  imageError?: string;
  videoUrl?: string;
  isGeneratingImage: boolean;
  isGeneratingVideo: boolean;
  videoGenerationOperation?: any; 
  videoError?: string;
  audioUrl?: string;
  isGeneratingAudio: boolean;
  audioError?: string;
  duration?: number;
  backgroundMusicUrl?: string;
  musicVolume?: number;
  speechVolume?: number;
}

export type AppStep = 'input' | 'config' | 'scenes';

export interface Toast {
  id: number;
  message: string;
  type: 'success' | 'error' | 'info';
}

export interface ProjectState {
    currentStep: AppStep;
    novelText: string;
    scenes: Scene[];
    characters: Character[];
    statusMessage: string;
    error: string;
    hasApiKey: boolean;
    imageStyle: string;
    artDirection: string;
    aspectRatio: '16:9' | '9:16';
    includeTextInImage: boolean;
    narratorVoice: string;
    isSaving: boolean;
    isProjectSaved: boolean;
    isMovieModalOpen: boolean;
    toasts: Toast[];
}

export type ProjectAction =
    | { type: 'SET_STEP'; payload: AppStep }
    | { type: 'SET_NOVEL_TEXT'; payload: string }
    | { type: 'SET_STATUS_MESSAGE'; payload: string }
    | { type: 'SET_ERROR'; payload: string }
    | { type: 'START_ANALYSIS' }
    | { type: 'ANALYZE_SUCCESS'; payload: Character[] }
    | { type: 'ANALYZE_FAILURE'; payload: string }
    | { type: 'START_SCENE_GENERATION' }
    | { type: 'SCENE_GENERATION_INITIALIZE'; payload: Scene[] }
    | { type: 'SCENE_GENERATION_COMPLETE' }
    | { type: 'SCENE_GENERATION_FAILURE'; payload: string }
    | { type: 'UPDATE_SCENE'; payload: { sceneId: number; updates: Partial<Scene> } }
    | { type: 'UPDATE_SCENES_ORDER'; payload: Scene[] }
    | { type: 'DELETE_SCENE'; payload: number }
    | { type: 'UPDATE_CHARACTER_VOICE'; payload: { characterName: string; newVoice: string } }
    | { type: 'SET_CONFIG'; payload: Partial<Pick<ProjectState, 'imageStyle' | 'artDirection' | 'aspectRatio' | 'includeTextInImage' | 'narratorVoice' | 'isSaving' | 'isProjectSaved'>> }
    | { type: 'UPDATE_SCENE_CONFIG', payload: { sceneId: number, config: Partial<Pick<Scene, 'backgroundMusicUrl' | 'musicVolume' | 'speechVolume'>>}}
    | { type: 'OPEN_MOVIE_MODAL' }
    | { type: 'CLOSE_MOVIE_MODAL' }
    | { type: 'LOAD_PROJECT'; payload: ProjectState }
    | { type: 'RESET_PROJECT' }
    | { type: 'SET_API_KEY_STATUS'; payload: boolean }
    | { type: 'ADD_TOAST'; payload: Omit<Toast, 'id'> }
    | { type: 'REMOVE_TOAST'; payload: number };

